const App: React.FC = () => {
  const { pathname } = useLocation();

  // Data State
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [showIntro, setShowIntro] = useState(true);

  // Check if we've already shown the intro in this session to avoid annoyance on refresh?
  // User requested: "when my website started" -> Implies fresh load. 
  // We can use sessionStorage if we want to persist "intro seen", but user request implies seeing it on load.
  // We'll default to showing it every hard refresh, but maybe not on route change (SPA navigation doesn't unmount App usually, but just in case).

  // Site config
  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    try {
      const saved = localStorage.getItem('ou_config');
      return saved ? JSON.parse(saved) : { heroImage: '' };
    } catch (e) {
      return { heroImage: '' };
    }
  });

  // Cart State
  const [cart, setCart] = useState<CartItem[]>(() => {
    try {
      const saved = localStorage.getItem('ou_cart');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // --- FIREBASE SUBSCRIPTIONS ---
  useEffect(() => {
    const unsubscribeProducts = subscribeToProducts((fetchedProducts) => {
      setProducts(fetchedProducts);
    });
    const unsubscribeOrders = subscribeToOrders((fetchedOrders) => {
      setOrders(fetchedOrders);
    });
    return () => {
      unsubscribeProducts();
      unsubscribeOrders();
    };
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('ou_config', JSON.stringify(siteConfig));
    } catch (e) {}
  }, [siteConfig]);

  useEffect(() => {
    try {
      localStorage.setItem('ou_cart', JSON.stringify(cart));
    } catch (e) {}
  }, [cart]);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);

  // Cart Handlers
  const handleAddToCart = (product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      return [...prev, { ...product, quantity: quantity }];
    });
  };

  const handleUpdateCartQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(1, item.quantity + delta) };
      }
      return item;
    }));
  };

  const handleRemoveFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const handleOrderComplete = () => {
    setCart([]);
  };

  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <>
      {showIntro && (
        <IntroOverlay 
           onComplete={() => setShowIntro(false)} 
           coverImage="https://i.postimg.cc/25fThJhj/5na55d0nvnrmt0cw34fsyzg77c.png"
        />
      )}

      <Routes>
        {/* Public Store Routes */}
        <Route path="/" element={
          <Layout cartCount={cartCount} products={products}>
            <StoreFront products={products} siteConfig={siteConfig} onAddToCart={handleAddToCart} />
          </Layout>
        } />

        <Route path="/product/:id" element={
          <Layout cartCount={cartCount} products={products}>
            <ProductDetails products={products} onAddToCart={handleAddToCart} />
          </Layout>
        } />

        <Route path="/collections/:name" element={
          <Layout cartCount={cartCount} products={products}>
            <CollectionView products={products} onAddToCart={handleAddToCart} />
          </Layout>
        } />

        <Route path="/cart" element={
          <Layout cartCount={cartCount} products={products}>
            <CartView 
              cart={cart}
              onUpdateQuantity={handleUpdateCartQuantity}
              onRemoveItem={handleRemoveFromCart}
            />
          </Layout>
        } />

        <Route path="/orders" element={
          <Layout cartCount={cartCount} products={products}>
            <OrderLookup />
          </Layout>
        } />

        <Route path="/checkout" element={
          <CheckoutView 
            cart={cart}
            onOrderSuccess={handleOrderComplete}
          />
        } />

        <Route path="/payment/callback" element={
          <PaymentCallback />
        } />

        {/* Admin Routes */}
        <Route path="/admin/login" element={
          <AdminLogin onLogin={() => setIsAuthenticated(true)} />
        } />

        <Route path="/admin/dashboard" element={
          isAuthenticated ? (
            <AdminDashboard 
              products={products}
              siteConfig={siteConfig}
              orders={orders}
              onUpdateProducts={setProducts}
              onUpdateSiteConfig={setSiteConfig}
              onUpdateOrders={setOrders}
              onLogout={() => setIsAuthenticated(false)}
            />
          ) : (
            <AdminLogin onLogin={() => setIsAuthenticated(true)} />
          )
        } />

        {/* Catch-all Route: Redirect to Home if 404 */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </>
  );
};

export default App;

