const PARAGRAPHS = [
  "For as long as I can remember I have been captivated by the world of make-believe. There is a special kind of magic that happens when you open a vintage storybook and for a moment the real world simply fades away. I have always wanted to take that feeling of wonder and turn it into something tangible something you can actually hold in your arms.",
  "In 2026 that dream finally found its home in Once Upon. We are beginning our journey with the baby blanket but to me it is so much more than just a piece of cloth. I wanted to create a collection where each design tells a story. Our little bear is the main character and he invites you to follow him on his painted adventures. Whether he is floating in a hot air balloon or discovering a hidden castle he is there to spark the imagination before your little one even falls asleep.",
  "As a mother of three I created this because I wanted to wrap my own children in that sense of whimsy. I love art that feels timeless and dreamy. Looking at these designs brings me a sense of peace and nostalgia and I wanted to share that quiet joy with you. It is a way to make the everyday moments of motherhood feel a little more like a fairy tale.",
  "Of course I know that a story is only good if it feels right. I was obsessive about finding a fabric that matches the softness of the art. I chose a material that truly breathes and feels airy and smooth against delicate skin because nothing matters more than the comfort of the babies we love so much.",
  "We do this for the wonder of childhood and the little dreamers who inspire us every day. I invite you to join us on this adventure and let our stories become a part of yours."
];

export const OurStory: React.FC = () => {
  const [visibleIndex, setVisibleIndex] = useState(-1);
  const containerRef = useRef<HTMLDivElement>(null);
  const [hasStarted, setHasStarted] = useState(false);

  useEffect(() => {
    // If the component is mounted on a separate page, we can start immediately
    // or keep the intersection observer if we want the effect to trigger only when scrolling into view
    // Since it's a dedicated page now, the user starts at the top.

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && !hasStarted) {
          setHasStarted(true);
          setVisibleIndex(0);
        }
      },
      { threshold: 0.1 } // Start when 10% visible
    );

    if (containerRef.current) {
      observer.observe(containerRef.current);
    }

    return () => observer.disconnect();
  }, [hasStarted]);

  useEffect(() => {
    if (hasStarted && visibleIndex < PARAGRAPHS.length + 1) {
      // Calculate delay based on previous paragraph length (simulating reading time)
      // Base delay 1500ms + variable
      const timer = setTimeout(() => {
        setVisibleIndex((prev) => prev + 1);
      }, 2500); // Fixed pace for a smooth "page turn" feel

      return () => clearTimeout(timer);
    }
  }, [visibleIndex, hasStarted]);

  return (
    <section className="min-h-screen py-32 bg-[#FFFDF9] relative overflow-hidden animate-fade-in">
       {/* Background decorative elements */}
       <div className="absolute top-0 left-0 w-full h-8 bg-gradient-to-b from-white to-transparent opacity-50"></div>
       <div className="absolute inset-0 bg-paper opacity-40 pointer-events-none"></div>

       <div ref={containerRef} className="container mx-auto px-6 max-w-3xl relative z-10">

         {/* Book Container */}
         <div className="relative bg-white/80 backdrop-blur-sm p-8 md:p-16 shadow-[0_10px_40px_rgba(217,196,184,0.2)] border border-brand-latte/20 rounded-[4px] md:rounded-[8px]">

            {/* Book Spine / Decorative Border */}
            <div className="absolute top-4 bottom-4 left-4 md:left-8 w-[1px] bg-brand-latte/20"></div>
            <div className="absolute top-4 bottom-4 right-4 md:right-8 w-[1px] bg-brand-latte/20"></div>

            {/* Header */}
            <div className={`text-center mb-12 transition-all duration-1000 transform ${hasStarted ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
               <div className="flex justify-center mb-4 text-brand-gold/60">
                 <Feather size={24} />
               </div>
               <span className="font-script text-3xl md:text-4xl text-brand-gold mb-2 block">
                 Our Story
               </span>
               <h2 className="font-serif text-xl md:text-2xl text-gray-900 tracking-wide uppercase">
                 A Note from the Founder
               </h2>
            </div>

            {/* Content Sequence */}
            <div className="space-y-8 md:px-12">
               {PARAGRAPHS.map((text, index) => (
                 <p 
                   key={index}
                   className={`font-serif text-lg md:text-xl leading-relaxed text-gray-700 transition-all duration-[2000ms] ease-out
                     ${index <= visibleIndex ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8 blur-sm'}
                   `}
                 >
                   {/* Drop Cap for first paragraph */}
                   {index === 0 && (
                     <span className="float-left text-5xl md:text-6xl font-script text-brand-flamingo pr-3 pt-2 leading-[0.8]">F</span>
                   )}
                   {/* Regular text for the rest, slicing first letter if index 0 */}
                   {index === 0 ? text.slice(1) : text}
                 </p>
               ))}

               {/* Signature */}
               <div className={`mt-12 pt-8 text-center transition-all duration-[2000ms] delay-500
                   ${visibleIndex > PARAGRAPHS.length - 1 ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}
               `}>
                  <div className="w-16 h-[1px] bg-brand-latte/40 mx-auto mb-6"></div>
                  <p className="font-script text-3xl md:text-4xl text-gray-900 relative inline-block">
                    Syahirah Kasim
                    <Sparkles size={14} className="absolute -top-2 -right-6 text-brand-gold animate-pulse" />
                  </p>
                  <p className="font-sans text-[10px] uppercase tracking-[0.2em] text-gray-400 mt-2">Founder & Creative Director</p>
               </div>
            </div>

            {/* Corner decorations */}
            <Star size={12} className="absolute top-6 right-6 text-brand-latte/40" />
            <Star size={12} className="absolute bottom-6 left-6 text-brand-latte/40" />

         </div>
       </div>
    </section>
  );
};

